-- Published 2010 Census redistricting counts for Washington congressional districts.
-- Column names use standard Census short forms (aian = American Indian and Alaska
-- Native, nhpi = Native Hawaiian and Other Pacific Islander); the full category label
-- for every column is spelled out in the .yml contract's descriptions.
-- caution: Wide 2010 Census (PL 94-171) redistricting cross-tab: one row per congressional_district, and every other column is a population count for a race/Hispanic-origin category, optionally narrowed to not-Hispanic (`_not_hispanic`) and/or to adults (`_18plus`). The count columns are overlapping subtotals, not a partition: `total_population_2010` equals the six `*_alone_2010` race columns plus `two_or_more_races_2010`, and separately equals `hispanic_any_race_2010` plus `not_hispanic_2010` (verified on the data). Hispanic origin is collected separately from race, so Hispanic residents also appear inside the race columns. Summing across columns counts the same people two or three times - pick the single column matching the category you want.
SELECT
    "_entity_id" AS entity_id,
    "_source_type" AS source_type,
    "_socrata_dataset_id" AS socrata_dataset_id,
    "congressional_district",
    CAST("total_population_2010" AS BIGINT) AS total_population_2010,
    CAST("population_of_one_race_2010" AS BIGINT) AS one_race_2010,
    CAST("white_alone_2010" AS BIGINT) AS white_alone_2010,
    CAST("black_or_african_american_alone_2010" AS BIGINT) AS black_alone_2010,
    CAST("american_indian_and_alaska_native_alone_2010" AS BIGINT) AS aian_alone_2010,
    CAST("asian_alone_2010" AS BIGINT) AS asian_alone_2010,
    CAST("native_hawaiian_and_other_pacific_islander_alone_2010" AS BIGINT) AS nhpi_alone_2010,
    CAST("some_other_race_alone_2010" AS BIGINT) AS other_race_alone_2010,
    CAST("population_of_two_or_more_races_2010" AS BIGINT) AS two_or_more_races_2010,
    CAST("hispanic_or_latino_of_any_race_2010" AS BIGINT) AS hispanic_any_race_2010,
    CAST("not_hispanic_or_latino_2010" AS BIGINT) AS not_hispanic_2010,
    CAST("population_of_one_race_not_hispanic_or_latino_2010" AS BIGINT) AS one_race_not_hispanic_2010,
    CAST("white_alone_not_hispanic_or_latino_2010" AS BIGINT) AS white_alone_not_hispanic_2010,
    CAST("black_or_african_american_alone_not_hispanic_or_latino_2010" AS BIGINT) AS black_alone_not_hispanic_2010,
    CAST("american_indian_and_alaska_native_alone_not_hispanic_or_latino_2010" AS BIGINT) AS aian_alone_not_hispanic_2010,
    CAST("asian_alone_not_hispanic_or_latino_2010" AS BIGINT) AS asian_alone_not_hispanic_2010,
    CAST("native_hawaiian_and_other_pacific_islander_alone_not_hispanic_or_latino_2010" AS BIGINT) AS nhpi_alone_not_hispanic_2010,
    CAST("some_other_race_alone_not_hispanic_or_latino_2010" AS BIGINT) AS other_race_alone_not_hispanic_2010,
    CAST("population_of_two_or_more_races_not_hispanic_or_latino_2010" AS BIGINT) AS two_or_more_races_not_hispanic_2010,
    CAST("total_population_over_18_2010" AS BIGINT) AS total_population_18plus_2010,
    CAST("population_of_one_race_over_18_2010" AS BIGINT) AS one_race_18plus_2010,
    CAST("white_alone_over_18_2010" AS BIGINT) AS white_alone_18plus_2010,
    CAST("black_or_african_american_alone_over_18_2010" AS BIGINT) AS black_alone_18plus_2010,
    CAST("american_indian_and_alaska_native_alone_over_18_2010" AS BIGINT) AS aian_alone_18plus_2010,
    CAST("asian_alone_over_18_2010" AS BIGINT) AS asian_alone_18plus_2010,
    CAST("native_hawaiian_and_other_pacific_islander_alone_over_18_2010" AS BIGINT) AS nhpi_alone_18plus_2010,
    CAST("some_other_race_alone_over_18_2010" AS BIGINT) AS other_race_alone_18plus_2010,
    CAST("population_of_two_or_more_races_over_18_2010" AS BIGINT) AS two_or_more_races_18plus_2010,
    CAST("hispanic_or_latino_of_any_race_over_18_2010" AS BIGINT) AS hispanic_any_race_18plus_2010,
    CAST("not_hispanic_or_latino_over_18_2010" AS BIGINT) AS not_hispanic_18plus_2010,
    CAST("population_of_one_race_not_hispanic_or_latino_over_18_2010" AS BIGINT) AS one_race_not_hispanic_18plus_2010,
    CAST("white_alone_not_hispanic_or_latino_over_18_2010" AS BIGINT) AS white_alone_not_hispanic_18plus_2010,
    CAST("black_or_african_american_alone_not_hispanic_or_latino_over_18_2010" AS BIGINT) AS black_alone_not_hispanic_18plus_2010,
    CAST("american_indian_and_alaska_native_alone_not_hispanic_or_latino_over_18_2010" AS BIGINT) AS aian_alone_not_hispanic_18plus_2010,
    CAST("asian_alone_not_hispanic_or_latino_over_18_2010" AS BIGINT) AS asian_alone_not_hispanic_18plus_2010,
    CAST("native_hawaiian_and_other_pacific_islander_alone_not_hispanic_or_latino_over_18_2010" AS BIGINT) AS nhpi_alone_not_hispanic_18plus_2010,
    CAST("some_other_race_alone_not_hispanic_or_latino_over_18_2010" AS BIGINT) AS other_race_alone_not_hispanic_18plus_2010,
    CAST("population_of_two_or_more_races_not_hispanic_or_latino_over_18_2010" AS BIGINT) AS two_or_more_races_not_hispanic_18plus_2010
FROM "washington-ofm-socrata-gexj-mqiq"
